public void testIndexOfAtEnd() {
    StrBuilder sb = new StrBuilder("abcdefgh");
    assertEquals(5, sb.indexOf("fgh", 0));
    assertEquals(5, sb.indexOf("fgh", 5));
    assertEquals(-1, sb.indexOf("fgh", 6));
}

public void testIndexOfAfterModification() {
    StrBuilder sb = new StrBuilder("aaabbbccc");
    sb.delete(3, 6);
    assertEquals(3, sb.indexOf("ccc", 0));
    assertEquals(-1, sb.indexOf("bbb", 0));
}

public void testIndexOfExactMatch() {
    StrBuilder sb = new StrBuilder("test");
    assertEquals(0, sb.indexOf("test", 0));
    sb.deleteFirst("test");
    assertEquals(-1, sb.indexOf("test", 0));
}
